int k = 3;

int maxSum = 0;
for (int i = 0; i <= numbers.size() - k; i++)
{
    int windowSum = 0;
    for (int j = i; j < i + k; j++) // recomputes the ENTIRE window sum every time
    {
        windowSum += numbers[j];
    }
    maxSum = max(maxSum, windowSum);
