#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

int main()
{
    vector<int> numbers = {2, 1, 5, 1, 3, 2};
    int k = 3;

    int windowSum = 0;
    for (int i = 0; i < k; i++)
    {
        windowSum += numbers[i]; // build the FIRST window normally
    }

    int maxSum = windowSum;

    for (int i = k; i < numbers.size(); i++)
    {
        windowSum = windowSum - numbers[i - k] + numbers[i]; // slide by one
        maxSum = max(maxSum, windowSum);
    }

    cout << maxSum << endl;

    return 0;
}

