using namespace std;

double findMaxAverage(vector<int> &nums, int k)
{
    int n = nums.size();
    int maxSum = INT_MIN;

    for (int i = 0; i <= n - k; i++)
    {
        int sum = 0;
        for (int j = i; j < i + k; j++) sum += nums[j];
        maxSum = max(maxSum, sum);
    }

    return (double)maxSum / k;
}

int main()
{
    vector<int> nums = {1, 12, -5, -6, 50, 3};

    cout << findMaxAverage(nums, 4) << endl;

    return 0;
}

